SELECT study_name, status
FROM gwas_studies
WHERE status = 'completed';

SELECT study_type, COUNT(*) AS study_count
FROM gwas_studies
GROUP BY study_type;

SELECT gene_id, AVG(average_pubmed_hits) AS avg_pubmed_hits
FROM gene_metrics
GROUP BY gene_id;

SELECT journal_name, pubmed_hits
FROM gene_publications
ORDER BY pubmed_hits DESC;

SELECT variant_id, gene_id, functional_impact
FROM gene_variants
WHERE functional_impact = 'nonsense';

SELECT AVG(interaction_strength) AS avg_strength
FROM gene_relationships
WHERE relationship_type = 'co-expression';
